import (
	"context"
	"net/http"
	"time"
)

// MetricsCollector is the interface used by Mux to report route hit
// metrics. Implementations can aggregate hit counts, response times,
// or forward the data to an external monitoring system.
type MetricsCollector interface {
	// RecordHit is called after a matched route handler has finished
	// serving a request, with the full route pattern and how long the
	// handler took to execute.
	RecordHit(ctx context.Context, r *http.Request, m RouteMetric)
}

// RouteMetric carries the data collected for a single request served by
// a matched route.
type RouteMetric struct {
	// Pattern is the full routing pattern that matched the request,
	// e.g. "/users/{id}".
	Pattern string

	// Method is the HTTP method of the request, e.g. "GET".
	Method string

	// Path is the actual request path that was routed.
	Path string

	// Duration is how long the matched handler took to serve the request.
	Duration time.Duration

	// URLParams are the URL parameters captured while matching the route.
	URLParams map[string]string
}

// SimpleMetricsCollector is a MetricsCollector implementation that invokes
// a user-supplied callback function for every recorded hit. It's a
// lightweight way to hook route metrics into an existing monitoring system
// without implementing the full MetricsCollector interface.
type SimpleMetricsCollector struct {
	// Fn is called for every route hit recorded.
	Fn func(m RouteMetric)
}

// RecordHit implements the MetricsCollector interface.
func (c *SimpleMetricsCollector) RecordHit(ctx context.Context, r *http.Request, m RouteMetric) {
	if c.Fn != nil {
		c.Fn(m)
	}
}
"}

